# terraform/branch_protection.tf
resource "github_branch_protection" "main" {
  repository_id = data.github_repository.claude_app.node_id
  pattern       = "main"

  enforce_admins         = true
  require_signed_commits = true

  required_status_checks {
    strict   = true
    contexts = ["lint-and-type", "unit-tests", "eval-suite", "drift-check"]
  }

  required_pull_request_reviews {
    required_approving_review_count = 2
    dismiss_stale_reviews           = true
    require_code_owner_reviews      = true
  }

  allows_force_pushes = false
  allows_deletions    = false
}

resource "github_branch_protection" "release_branches" {
  repository_id = data.github_repository.claude_app.node_id
  pattern       = "release/*"

  enforce_admins = false  # release-manager team can bypass if needed

  required_status_checks {
    strict   = true
    contexts = ["lint-and-type", "eval-suite-full", "release-integrity"]
  }

  required_pull_request_reviews {
    required_approving_review_count = 1
    dismiss_stale_reviews           = true
  }

  push_restrictions = [
    data.github_team.release_managers.node_id
  ]

  allows_force_pushes = false
  allows_deletions    = false
}

# Branch protection for prompt/ branches
resource "github_branch_protection" "prompt_branches" {
  repository_id = data.github_repository.claude_app.node_id
  pattern       = "prompt/*"

  required_status_checks {
    strict   = false  # Does not need to be up-to-date with main (short-lived branches)
    contexts = [
      "lint-and-type",
      "unit-tests",
      "eval-suite",
      "drift-check",
      "branch-lifetime-check",
    ]
  }

  required_pull_request_reviews {
    required_approving_review_count = 1
    dismiss_stale_reviews           = true
  }

  allows_force_pushes = false
  allows_deletions    = true  # Short-lived branches may be deleted after merge
}

