# Run this in CI (weekly schedule) to verify protection rules have not drifted

import sys

def audit_branch_protection(repo: str, token: str) -> bool:
    import urllib.request, json

    headers = {
        "Authorization": f"Bearer {token}",
        "Accept": "application/vnd.github+json",
        "X-GitHub-Api-Version": "2022-11-28",
    }

    def get_protection(branch: str) -> dict:
        url = f"https://api.github.com/repos/{repo}/branches/{branch}/protection"
        req = urllib.request.Request(url, headers=headers)
        try:
            with urllib.request.urlopen(req) as resp:
                return json.loads(resp.read())
        except Exception as e:
            return {"error": str(e)}

    all_ok = True

    # Check main branch
    main_prot = get_protection("main")
    if "error" in main_prot:
        print(f"FAIL: Could not read main branch protection: {main_prot['error']}")
        all_ok = False
    else:
        required_checks = {c["context"] for c in
                           main_prot.get("required_status_checks", {}).get("checks", [])}
        for check in ["lint-and-type", "unit-tests", "eval-suite", "drift-check"]:
            if check not in required_checks:
                print(f"FAIL: Required check '{check}' missing from main branch protection")
                all_ok = False

        approvals = main_prot.get("required_pull_request_reviews", {}).get(
            "required_approving_review_count", 0)
        if approvals < 2:
            print(f"FAIL: main branch requires {approvals} approvals (expected >= 2)")
            all_ok = False

        if not main_prot.get("allow_force_pushes") == False:
            print("FAIL: main branch allows force pushes — must be disabled")
            all_ok = False

    if all_ok:
        print("OK: Branch protection rules are compliant.")
    return all_ok

if __name__ == "__main__":
    import os
    repo = os.environ.get("GITHUB_REPOSITORY", "YOUR-ORG/claude-app")
    token = os.environ.get("GITHUB_TOKEN", "")
    sys.exit(0 if audit_branch_protection(repo, token) else 1)
